import { tryGetCueingConfiguration } from './configure';
import type { CueModalId } from './ports';

export const shouldUserSeeCue = async (modalId: CueModalId): Promise<boolean> => {
  const configuration = tryGetCueingConfiguration();
  if (!configuration) {
    return false;
  }

  const { modalHistory, onError, registry } = configuration;
  const config = registry[modalId];
  if (!config) {
    onError.log({ context: 'shouldUserSeeCue', modalId, reason: 'unknown_modal_id' });
    return false;
  }

  try {
    return await modalHistory.shouldUserSeeModal(modalId);
  } catch (error) {
    onError.log({ context: 'shouldUserSeeCue', modalId }, error);
    return false;
  }
};
